// Shared tokenizer for the in-book search feature.
//
// IMPORTANT: this exact module is imported by BOTH the build-time index
// generator (scripts/build-search-index.mjs) and the runtime search client
// (src/services/search/searchClient.js). The query must be tokenized the same
// way the index was, or query tokens will never line up with index tokens and
// search silently returns nothing. Keep it dependency-free (no React, no Node
// APIs) so both environments can load it as plain ESM.
//
// Strategy — tuned for Chinese-dominant content:
//   • CJK runs    -> overlapping bigrams (好用 in "他好用" gives 他好, 好用).
//                    Bigrams give precision without a real word segmenter.
//                    A length-1 CJK run emits that single char as a fallback.
//   • Latin/digit -> whole word, lowercased ("Rust" and "rust" collide).
//   • Everything else (punctuation, whitespace, symbols) is a separator.

// Matches one CJK ideograph (Unified + Extension A + Compatibility).
const CJK_CHAR = /[㐀-鿿豈-﫿]/;
// Matches one latin/digit token character.
const WORD_CHAR = /[a-z0-9]/;

function isCjk(ch) {
  return CJK_CHAR.test(ch);
}

function isWord(ch) {
  return WORD_CHAR.test(ch);
}

// Tokenize raw text into the bag of search tokens. Returns a flat array that
// may contain duplicates — callers that need term frequency just count them.
export function tokenize(text) {
  const input = String(text || '').toLowerCase();
  const tokens = [];

  let i = 0;
  const len = input.length;

  while (i < len) {
    const ch = input[i];

    if (isCjk(ch)) {
      // Collect the whole CJK run, then emit overlapping bigrams.
      let j = i;
      while (j < len && isCjk(input[j])) {
        j += 1;
      }
      const run = input.slice(i, j);
      if (run.length === 1) {
        tokens.push(run);
      } else {
        for (let k = 0; k < run.length - 1; k += 1) {
          tokens.push(run.slice(k, k + 2));
        }
      }
      i = j;
      continue;
    }

    if (isWord(ch)) {
      let j = i;
      while (j < len && isWord(input[j])) {
        j += 1;
      }
      tokens.push(input.slice(i, j));
      i = j;
      continue;
    }

    // Separator: skip.
    i += 1;
  }

  return tokens;
}

// Count term frequency for the unique tokens of a piece of text.
// Returns a Map<token, count>.
export function tokenizeWithFreq(text) {
  const freq = new Map();
  for (const token of tokenize(text)) {
    freq.set(token, (freq.get(token) || 0) + 1);
  }
  return freq;
}

// Heading -> anchor id. Single source of truth: src/utils/markdown.js re-exports
// this, and the article renderer (src/components/docs/markdownRenderers.js)
// assigns it as each heading's DOM id, while the build-time index generator uses
// it for section anchors. One function means a search result's #anchor always
// resolves to a real heading instead of silently landing at the article top.
export function slugifyHeading(text) {
  return encodeURIComponent(
    String(text || '')
      .toLowerCase()
      .trim()
      .replace(/[\s_]+/g, '-')
      .replace(/^-+|-+$/g, '')
  )
    .replace(/%20/g, '-')
    .replace(/[!'()*]/g, (char) => char)
    .replace(/%2D/g, '-');
}
